#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isValid(string s) {
        stack<char> st;
        unordered_map<char, char> bracket_map = {{')', '('}, {'}', '{'}, {']', '['}};

        for (char bracket : s) {
            if (bracket_map.find(bracket) == bracket_map.end()) {
                st.push(bracket);
            } else {
                if (st.empty() || st.top() != bracket_map[bracket]) {
                    return false;
                }
                st.pop();
            }
        }

        return st.empty();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s;
    if (!(cin >> s)) return 0;
    Solution sol;
    bool ans = sol.isValid(s);
    cout << boolalpha << ans << endl;
    return 0;
}
